parameters.jsCode:
const alert = $input.first().json;

const threatMap = {
  'Terminal shell in container': { category: 'shell-in-container', severity: 'SEV2', contain: true },
  'Privilege Escalation in Container': { category: 'privilege-escalation', severity: 'SEV1', contain: true },
  'Launch Privileged Container': { category: 'privileged-container', severity: 'SEV1', contain: true },
  'Container Drift Detected': { category: 'container-drift', severity: 'SEV2', contain: false },
  'Kubernetes Client Tool Launched in Container': { category: 'kubectl-in-container', severity: 'SEV1', contain: true },
  'Write below root': { category: 'rootfs-write', severity: 'SEV2', contain: false },
  'Netcat Remote Code Execution in Container': { category: 'rce', severity: 'SEV1', contain: true },
  'Create Symlink Over Sensitive Files': { category: 'symlink-attack', severity: 'SEV2', contain: true },
  'Sudo Potential Privilege Escalation': { category: 'sudo-escalation', severity: 'SEV1', contain: true }
};

const ruleName = alert.rule || 'Unknown';
const context = Object.entries(threatMap).find(([k]) => ruleName.includes(k))?.[1] || 
  { category: 'generic-k8s-threat', severity: 'SEV2', contain: false };

const fields = alert.output_fields || {};

return [{
  json: {
    incidentId: 'K8S-' + Date.now().toString(36).toUpperCase(),
    ruleName,
    threatCategory: context.category,
    severity: context.severity,
    shouldContain: context.contain,
    priority: alert.priority,
    podName: fields['k8s.pod.name'] || fields['container.name'] || 'unknown',
    namespace: fields['k8s.ns.name'] || 'unknown',
    containerName: fields['container.name'] || 'unknown',
    containerId: fields['container.id'] || 'unknown',
    image: fields['container.image.repository'] + ':' + (fields['container.image.tag'] || 'latest'),
    processName: fields['proc.name'] || 'unknown',
    processCmd: fields['proc.cmdline'] || 'unknown',
    userName: fields['user.name'] || 'unknown',
    nodeHostname: fields['k8s.node.name'] || fields['container.id'] || 'unknown',
    timestamp: alert.time || new Date().toISOString(),
    rawOutput: alert.output
  }
}];

